class Animal {
    var isAlive = true
    func run() {
        print("The animal is running!")
    }
}

// Cat inherits from Animal
class Cat: Animal {
    var hasNineLives = true
}

let garfield = Cat()
print("Is Garfield alive? \(garfield.isAlive)")
garfield.run()
